<script>
import DB from '@/database/index.js'
import EventBus from '@/event-bus.js'

import TsBarChart from './BarChart.vue'
import TsEventDetail from './EventDetail.vue'
import TsEventTagMenu from './EventTagMenu.vue'
import EventTagDialog from './EventTagDialog.vue'
import TsEventActionMenu from './EventActionMenu.vue'
import TsEventTags from './EventTags.vue'
import WelcomeCard from './WelcomeCard.vue'
import SearchNotFoundCard from './SearchNotFoundCard.vue'

const defaultQueryFilter = () => {
  return {
    from: 0,
    terminate_after: 40,
    size: 40,
    uploadIds: ['_all'],
    order: 'desc',
    chips: [],
  }
}

const emptyEventList = () => {
  return {
    meta: {
      count_per_data_export: {},
      num_events: 0,
      num_states: 0,
      has_next_page: false,
    },
    objects: [],
  }
}

export default {
  components: {
    TsBarChart,
    TsEventDetail,
    TsEventTagMenu,
    EventTagDialog,
    TsEventActionMenu,
    TsEventTags,
    WelcomeCard,
    SearchNotFoundCard,
  },
  props: {
    queryRequest: {
      type: Object,
      default: () => {},
    },
    itemsPerPage: {
      type: Number,
      default: 40,
    },
    disableSaveSearch: {
      type: Boolean,
      default: true,
    },
    disableHistogram: {
      type: Boolean,
      default: true,
    },
    disableColumns: {
      type: Boolean,
      default: false,
    },
    disableSettings: {
      type: Boolean,
      default: false,
    },
    disablePagination: {
      type: Boolean,
      default: false,
    },
    highlightEvent: {
      type: Object,
      default: () => {},
    },
  },
  data() {
    return {
      showEventTagMenu: false,
      columnHeaders: [
        {
          text: '',
          value: 'field',
        },
      ],
      tableOptions: {
        itemsPerPage: this.itemsPerPage,
      },
      isSummaryLoading: false,
      currentItemsPerPage: this.itemsPerPage,
      expandedRows: [],
      selectedFields: [{ field: 'event_type_msg', type: 'text' }],
      searchColumns: '',
      columnDialog: false,
      saveSearchMenu: false,
      saveSearchFormName: '',
      saveSearchNameRules: [(v) => !!v || 'Name is required.', (v) => (v && v.length <= 255) || 'Name is too long.'],
      selectedEventTags: [],
      tagConfig: {
        good: { color: 'green', textColor: 'white', label: 'mdi-check-circle-outline' },
        bad: { color: 'red', textColor: 'white', label: 'mdi-alert-circle-outline' },
        suspicious: { color: 'orange', textColor: 'white', label: 'mdi-help-circle-outline' },
      },
      searchInProgress: false,
      exportDialog: false,
      currentPage: 1,
      eventList: {
        meta: {},
        objects: [],
      },
      currentQueryString: '',
      currentQueryFilter: defaultQueryFilter(),
      selectedEvents: [],
      displayOptions: {
        isCompact: false,
        showTags: true,
        showMillis: false,
        showDataExportName: true,
        showSourceFile: false,
      },
      showHistogram: false,
      branchParent: null,
      sortOrderAsc: true,
      summaryCollapsed: false,
      showBanner: false,
      isFirstSearch: true,
    }
  },
  computed: {
    summaryInfoMessage() {
      const totalEvents = this.eventList.meta.summary_event_count
      const uniqueEvents = this.eventList.meta.summary_unique_event_count
      return `[experimental] This summary is based on the message field on your current page (${totalEvents} rows, ${uniqueEvents} unique message fields).`
    },
    project() {
      return this.$store.state.project
    },
    meta() {
      return this.$store.state.meta
    },
    highlightEventId() {
      if (this.highlightEvent) {
        return this.highlightEvent._id
      }
      return null
    },
    totalHits() {
      // Use total_count from metadata (represents ALL matching events, not just current page)
      return this.eventList.meta.total_count || 0;
    },
    totalHitsForPagination() {
      // Return actual total hits from the database
      // Vuetify uses this for the "1-100 of X" display
      return this.totalHits;
    },
    totalTime() {
      return this.eventList.meta.query_time_ms / 1000 || 0
    },
    fromEvent() {
      return this.currentQueryFilter.from || 1
    },
    toEvent() {
      if (this.totalHits < this.currentQueryFilter.size) {
        return
      }
      return parseInt(this.currentQueryFilter.from) + parseInt(this.currentQueryFilter.size)
    },
    timeFilterChips: function () {
      return this.currentQueryFilter.chips.filter((chip) => chip && chip.type && chip.type.startsWith('datetime'))
    },
    currentSearchNode() {
      return this.$store.state.currentSearchNode
    },
    userSettings() {
      return this.$store.state.settings
    },
    headers() {
      let baseHeaders = [
        {
          text: '',
          value: 'data-table-select',
          sortable: false,
        },
        {
          value: 'actions',
          width: '105',
          sortable: false,
        },
        {
          text: `Datetime (${this.$store.state.localTimezoneAbbr}) `,
          align: 'start',
          value: '_source.primary_timestamp',
          width: '200',
          sortable: true,
        },
        // {
        //   value: '_source.comment',
        //   width: '40',
        //   sortable: false,
        // },
      ]
      let extraHeaders = []
      this.selectedFields.forEach((field) => {
        let header = {
          text: field.field !== 'event_type_msg' ? field.field : 'Event Type',
          align: 'start',
          value: '_source.' + field.field,
          sortable: false,
        }
        if (field.field === 'event_type_msg') {
          header.width = '100%'
          // header.text = 'Event Type'
          extraHeaders.unshift(header)
        } else {
          extraHeaders.push(header)
        }
      })

      // Extend the column headers from position 3 (after the actions column)
      baseHeaders.splice(3, 0, ...extraHeaders)

      // Add Device column first
      baseHeaders.push({
        value: '_source.device_profiles_data',
        text: 'Device',
        align: 'center',
        width: '200',
        sortable: false,
      })
      // Add export name based on configuration
      if (this.displayOptions.showDataExportName) {
        baseHeaders.push({
          value: 'data_export_name',
          align: 'end',
          sortable: false,
        })
      }
      if (this.displayOptions.showSourceFile) {
        baseHeaders.push({
          value: 'source_file',
          text: 'Source file',
          align: 'end',
          sortable: false,
        })
      }
      // console.log('[EventList.headers] Generated headers:', baseHeaders)
      return baseHeaders
    },

    activeContext() {
      return this.$store.state.activeContext
    },
    settings() {
      return this.$store.state.settings
    },
    filterChips: function () {
      return this.currentQueryFilter.chips.filter((chip) => chip && chip.type && (chip.type === 'label' || chip.type === 'attribute'))
    },
    availableColumns() {
      if (!this.meta || !this.meta.mappings) return [];
      const excluded = ['id', 'event_category', 'tags', 'labels', 'event_kind', 'data_export_id', 'event_outcome'];
      return this.meta.mappings.filter(m => !excluded.includes(m.field));
    },
  },
  methods: {
    toggleSummary() {
          this.summaryCollapsed = !this.summaryCollapsed;
          localStorage.setItem('aiSummaryCollapsed', String(this.summaryCollapsed));
    },

    sortEvents(sortDesc) {
      // sortDesc is the value of Vuetify's sort-desc (true = descending, false = ascending)
      if (sortDesc) {
        this.currentQueryFilter.order = 'desc'
      } else {
        this.currentQueryFilter.order = 'asc'
      }
      this.search(true, true, false)
    },
    getFieldName: function (field) {
      if (field === 'Event Type') {
        return 'item._source.event_type_msg'
      }
      return 'item._source.' + field
    },
    toggleDetailedEvent: function (row) {
      let index = this.expandedRows.findIndex((x) => x._id === row._id)
      if (this.expandedRows.some((event) => event._id === row._id)) {
        if (row.showDetails) {
          row['showDetails'] = false
          this.expandedRows.splice(index, 1)
          this.$set(row, 'showComments', false)
        } else {
          row['showDetails'] = true
          this.expandedRows.splice(index, 1)
          this.expandedRows.push(row)
          if (this.$store.state.demoMode) {
            EventBus.$emit('demo:action', 'event-expanded')
          }
          return
        }

        if (row.deltaDays) {
          this.expandedRows.splice(index, 1)
          this.expandedRows.push(row)
        }
      } else {
        row['showDetails'] = true
        this.expandedRows.push(row)
        if (this.$store.state.demoMode) {
          EventBus.$emit('demo:action', 'event-expanded')
        }
      }
    },
    newComment: function (row) {
      if (row.showDetails) {
        this.$set(row, 'showComments', true)
      } else {
        this.$set(row, 'showComments', true)
        this.toggleDetailedEvent(row)
      }
    },
    addTimeBubbles: function () {
      this.expandedRows = []
      this.eventList.objects.forEach((event, index) => {
        if (index < 1) {
          return
        }
        let prevEvent = this.eventList.objects[index - 1]
        let timestampMillis = this.$options.filters.formatTimestamp(event._source.primary_timestamp)
        let prevTimestampMillis = this.$options.filters.formatTimestamp(prevEvent._source.primary_timestamp)
        let timestamp = Math.floor(timestampMillis / 1000)
        let prevTimestamp = Math.floor(prevTimestampMillis / 1000)
        let delta = Math.floor(timestamp - prevTimestamp)
        // In descending order (most recent first), prevEvent has later timestamp, so flip the delta
        if (this.currentQueryFilter.order === 'desc') {
          delta = Math.floor(prevTimestamp - timestamp)
        }
        let deltaDays = Math.floor(delta / 60 / 60 / 24)
        if (deltaDays > 0) {
          prevEvent['deltaDays'] = deltaDays
          this.expandedRows.push(prevEvent)
        }
      })
    },
    getDataExport: function (event) {
      // Browser model: events have data_export_id directly
      const deID = event._source.data_export_id
      const dataExport = this.project.dataExports.find((de) => de.id === deID)
      if (!dataExport) {
        console.warn('[EventList.getDataExport] Data export not found for id:', deID)
        return { name: 'Unknown Data Export', id: deID, color: '#999' }
      }
      return dataExport
    },
    getDataExportColor(event) {
      let dataExport = this.getDataExport(event)
      let backgroundColor = dataExport.color || '#999'
      if (!backgroundColor.startsWith('#')) {
        backgroundColor = '#' + backgroundColor
      }
      if (this.$vuetify.theme.dark) {
        return {
          'background-color': backgroundColor,
          filter: 'grayscale(25%)',
          color: '#333',
        }
      }
      return {
        'background-color': backgroundColor,
      }
    },
    getTimeBubbleColor() {
      let backgroundColor = '#f5f5f5'
      if (this.$vuetify.theme.dark) {
        backgroundColor = '#333'
      }
      return {
        'background-color': backgroundColor,
      }
    },
    getDeviceProfileLabel(profile) {
      if (!profile) return ''
      if (profile.user_label && profile.user_label.trim()) {
        return `${profile.user_label} (${profile.model})`
      }
      return profile.model || ''
    },
    getAllUploadIds: function () {
      // Browser model: return IDs directly
      return this.project.dataExports.map((de) => de.id)
    },
    search: async function (resetPagination = true, incognito = false, parent = false) {
      // Exit early if there are no uploadIds selected
      if (this.currentQueryFilter.uploadIds && !this.currentQueryFilter.uploadIds.length) {
        this.eventList = emptyEventList()
        EventBus.$emit('updateCountPerExport', {})
        this.$emit('countPerDataExport', {})
        EventBus.$emit('searchResultsCounts', {
          countPerEventType: {},
          countPerIPAddress: {},
          countPerTagOrLabel: {}
        })
        return
      }

      // Expand '_all' to all data export IDs (handle both array ['_all'] and string '_all')
      const uploadIds = this.currentQueryFilter.uploadIds;
      if (
        uploadIds === '_all' || 
        (Array.isArray(uploadIds) && (uploadIds.length === 0 || uploadIds[0] === '_all'))
      ) {
        const allUploadIds = this.getAllUploadIds();
        this.currentQueryFilter.uploadIds = allUploadIds;
      }

      // Allow searches with empty query string (shows all events from selected data export)
      this.searchInProgress = true
      this.selectedEvents = []
      this.eventList = emptyEventList()

      if (resetPagination) {
        this.tableOptions.page = 1
        this.currentPage = 1
        this.currentItemsPerPage = this.tableOptions.itemsPerPage
        this.currentQueryFilter.size = this.tableOptions.itemsPerPage
        this.currentQueryFilter.from = 0
      }

      const startTime = Date.now()
      
      try {
        const response = await DB.searchEvents(this.currentQueryString, this.currentQueryFilter)

        // Response has unwrapped format:
        // - objects: array of {_id, _source} wrapped events
        // - meta: metadata including count_per_data_export, total_count, etc.
        this.eventList.objects = response.objects || []
        this.eventList.meta = response.meta || {
          count_per_data_export: {},
          total_count: 0,
        }
        
        // Calculate has_next_page based on pagination
        const currentFrom = this.currentQueryFilter.from || 0
        this.eventList.meta.has_next_page = (currentFrom + this.eventList.objects.length) < this.eventList.meta.total_count
        this.eventList.meta.query_time_ms = Date.now() - startTime

        this.updateShowBanner()
        this.$emit('countPerDataExport', this.eventList.meta.count_per_data_export)
        EventBus.$emit('updateCountPerExport', this.eventList.meta.count_per_data_export)
        EventBus.$emit('searchResultsCounts', {
          countPerEventType: this.eventList.meta.count_per_event_type || {},
          countPerIPAddress: this.eventList.meta.count_per_ip_address || {},
          countPerTagOrLabel: this.eventList.meta.count_per_tag_or_label || {}
        })
        
        this.addTimeBubbles()
        
        if (this.isFirstSearch) {
          this.isFirstSearch = false
          this.$emit('initialSearchComplete')
        }
      } catch (error) {
        console.error('[EventList] Error searching:', error)
        this.errorSnackBar('Error fetching search results: ' + error.message)
      } finally {
        this.searchInProgress = false
      }
    },
    exportSearchResult: function () {
      // TODO: Implement CSV export for browser model
      this.exportDialog = false
    },
    addChip: function (chip) {
      if (!this.currentQueryFilter.chips) {
        this.currentQueryFilter.chips = []
      }
      this.currentQueryFilter.chips.push(chip)
      this.search()
    },
    removeChip: function (chip, search = true) {
      let chipIndex = this.currentQueryFilter.chips.findIndex((c) => c.value === chip.value)
      this.currentQueryFilter.chips.splice(chipIndex, 1)
      if (search) {
        this.search()
      }
    },
    removeChips: function (chips, search = true) {
      if (!Array.isArray(chips)) {
        this.errorSnackBar('Not an array of chips')
        return
      }
      chips.forEach((chip) => {
        this.removeChip(chip, false)
      })
      if (search) {
        this.search()
      }
    },
    addChipFromHistogram: function (chip) {
      if (!this.currentQueryFilter.chips) {
        this.currentQueryFilter.chips = []
      }
      this.currentQueryFilter.chips.forEach((chip) => {
        if (chip.type === 'datetime_range') {
          this.removeChip(chip, false)
        }
      })
      this.addChip(chip)
    },
    paginate: function () {
      // Reset pagination if number of pages per page changes.
      if (this.tableOptions.itemsPerPage !== this.currentItemsPerPage) {
        this.tableOptions.page = 1
        this.currentPage = 1
        this.currentItemsPerPage = this.tableOptions.itemsPerPage
        this.currentQueryFilter.size = this.tableOptions.itemsPerPage
        this.search(true, true)
        return
      }
      // To avoid double search request exit early if this is the first search for this
      // search session.
      if (this.currentPage === this.tableOptions.page) {
        return
      }
      this.currentQueryFilter.from =
        this.tableOptions.page * this.currentQueryFilter.size - this.currentQueryFilter.size
      this.currentPage = this.tableOptions.page
      this.search(false, true)
    },
    updateSelectedFields: function (value) {
      // If we haven't fetched the field before, do an new search.
      value.forEach((field) => {
        if (!this.headers.filter((e) => e.field === field.field).length > 0) {
          this.search(true, true)
        }
      })
    },
    removeField: function (index) {
      this.selectedFields.splice(index, 1)
    },
    toggleStar(event) {
      // Ensure labels array exists
      if (!event._source.labels) {
        event._source.labels = []
      }
      
      // Determine if we're adding or removing the star
      // Determine if we're adding or removing the star
      const isStarred = event._source.starred === 1;
      
      if (isStarred) {
        event._source.starred = 0
        if (event._source.labels) {
          const idx = event._source.labels.indexOf('starred')
          if (idx > -1) event._source.labels.splice(idx, 1)
        }
        this.$store.dispatch('updateEventLabels', { label: 'starred', num: -1 })
        DB.removeLabelEvent([event._id], ['starred']).catch(e => {
          console.error('Error updating star in database:', e)
        })
      } else {
        event._source.starred = 1
        if (!event._source.labels) {
          event._source.labels = []
        }
        event._source.labels.push('starred')
        this.$store.dispatch('updateEventLabels', { label: 'starred', num: 1 })
        DB.addLabelEvent([event._id], ['starred']).catch(e => {
          console.error('Error updating star in database:', e)
        })
      }
    },
    toggleMultipleStars: function () {
      let netStarCountChange = 0
      const eventsToStar = []
      const eventsToUnstar = []
      
      this.selectedEvents.forEach((event) => {
        if (event._source.starred === 1) {
          event._source.starred = 0
          if (event._source.labels) {
            const idx = event._source.labels.indexOf('starred')
            if (idx > -1) event._source.labels.splice(idx, 1)
          }
          eventsToUnstar.push(event._id)
          netStarCountChange--
        } else {
          event._source.starred = 1
          if (!event._source.labels) {
            event._source.labels = []
          }
          event._source.labels.push('starred')
          eventsToStar.push(event._id)
          netStarCountChange++
        }
      })
      
      // Update global store reactive count
      if (netStarCountChange !== 0) {
        this.$store.dispatch('updateEventLabels', { label: 'starred', num: netStarCountChange })
      }
      
      // Persist changes to database
      if (eventsToStar.length > 0) {
        DB.addLabelEvent(eventsToStar, ['starred']).catch(e => {
          console.error('Error starring events:', e)
        })
      }
      if (eventsToUnstar.length > 0) {
        DB.removeLabelEvent(eventsToUnstar, ['starred']).catch(e => {
          console.error('Error unstarring events:', e)
        })
      }
      this.selectedEvents = []
    },
    saveSearch: function () {
      // Saved searches not implemented in browser-only version
      this.$store.dispatch('setSnackBar', {
        message: 'Saved searches are not available in browser-only mode',
        color: 'info',
        timeout: 3000,
      })
      this.saveSearchFormName = ''
      this.saveSearchMenu = false
    },
    updateShowBanner: function() {
      // Show banner only when processing a are enabled and at
      // least one enabled export is in "processing" state.
      // Browser model: status is a string, not an array
      this.showBanner =
        !!this.settings.showProcessingData &&
        this.project.dataExports
          .filter(tl => this.$store.state.enabledDataExports.includes(tl.id))
          .some(tl => tl.status === 'processing')
    },

  },
  watch: {
    tableOptions: {
      handler(newVal, oldVal) {
        // Return early if the sort order changed.
        // The search is done in the sortEvents method.
        if (oldVal.sortDesc === undefined) return
        if (newVal.sortDesc[0] !== oldVal.sortDesc[0]) return

        this.paginate()
      },
      deep: true,
    },
    queryRequest: {
      handler(newQueryRequest, oldqueryRequest) {
        // Return early if this isn't a new request.
        if (newQueryRequest === oldqueryRequest || !newQueryRequest) {
          return
        }
        this.currentQueryString = newQueryRequest.queryString || ''
        this.currentQueryFilter = newQueryRequest.queryFilter || defaultQueryFilter()
        this.currentQueryDsl = newQueryRequest.queryDsl || null
        let resetPagination = newQueryRequest['resetPagination'] || false
        let incognito = newQueryRequest['incognito'] || false
        let parent = newQueryRequest['parent'] || false
        // Set additional fields. This is used when loading filter from a saved search.
        if (this.currentQueryFilter.fields) {
          this.selectedFields = this.currentQueryFilter.fields
        }
        // Preserve user defined sort order.
        if (this.sortOrderAsc) {
          this.currentQueryFilter.order = 'asc'
        } else {
          this.currentQueryFilter.order = 'desc'
        }
        this.search(resetPagination, incognito, parent)
      },
      deep: true,
    },
    'settings.showProcessingData': {
      handler() {
        this.updateShowBanner()
      },
    },
  },
  created() {
    const storedState = localStorage.getItem('aiSummaryCollapsed');
    if (storedState === 'true') {
      this.summaryCollapsed = true;
    }
    
    if (this.queryRequest && this.queryRequest.queryString) {
      this.currentQueryString = this.queryRequest.queryString
      this.currentQueryFilter = { ...this.queryRequest.queryFilter } || defaultQueryFilter()
      this.currentQueryDsl = { ...this.queryRequest.queryDsl }
      if (this.currentQueryFilter.fields) {
        this.selectedFields = this.currentQueryFilter.fields
      }
    }
    
    this.search()
  },
  mounted() {
    // Demo mode: allow programmatic row expansion/collapse
    EventBus.$on('demo:force-expand-first-row', () => {
        const attemptExpand = () => {
            if (this.eventList.objects.length > 0 && !this.searchInProgress) {
                const first = this.eventList.objects[0]
                if (!this.expandedRows.some(r => r._id === first._id)) {
                    this.toggleDetailedEvent(first)
                }
                return true
            }
            return false
        }

        if (!attemptExpand()) {
            // If data is not ready, retry for up to 2 seconds
            let retries = 0
            const interval = setInterval(() => {
                retries++
                if (attemptExpand() || retries > 20) {
                    clearInterval(interval)
                }
            }, 100)
        }
    })
    EventBus.$on('demo:force-collapse-all', () => {
        this.expandedRows = []
    })
  },
  beforeDestroy() {
    EventBus.$off('demo:force-expand-first-row')
    EventBus.$off('demo:force-collapse-all')
  }
}
</script>


